import React, { useState, useEffect } from 'react';
import axios from 'axios';
import { Search, ShoppingCart, Filter, Store, MapPin } from 'lucide-react';
import { URL_CARPETA_IMAGENES } from '../utils/helpers';
import { useSearchParams } from 'react-router-dom';

const VistaCliente = () => {
  const [productos, setProductos] = useState([]);
  const [categoriaActiva, setCategoriaActiva] = useState('Todos');
  const [loading, setLoading] = useState(true);
  const [searchParams] = useSearchParams();
  
  // Capturamos la búsqueda desde el Header (URL)
  const queryBusqueda = searchParams.get('search') || '';

  const categorias = [
    'Todos', 'Almacén', 'Bebidas', 'Lácteos', 'Carnicería', 
    'Frutas y Verduras', 'Limpieza', 'Perfumería', 'Mascotas'
  ];

  useEffect(() => {
    fetchProductos();
  }, []);

  const fetchProductos = async () => {
    try {
      // Importante: El backend debe hacer .populate('local') para traer el nombre del comercio
      const res = await axios.get(`${process.env.REACT_APP_API_URL}/api/ofertas`);
      setProductos(res.data);
    } catch (error) {
      console.error("Error al cargar productos");
    } finally {
      setLoading(false);
    }
  };

  const productosFiltrados = productos.filter(p => {
    const coincideCategoria = categoriaActiva === 'Todos' || p.categoria === categoriaActiva;
    const coincideBusqueda = p.producto.toLowerCase().includes(queryBusqueda.toLowerCase()) || 
                             p.local?.nombre.toLowerCase().includes(queryBusqueda.toLowerCase());
    return coincideCategoria && coincideBusqueda;
  });

  return (
    <div style={containerStyle}>
      {/* SELECTOR DE CATEGORÍAS */}
      <div style={scrollCategories}>
        {categorias.map(cat => (
          <button 
            key={cat} 
            onClick={() => setCategoriaActiva(cat)}
            style={categoriaActiva === cat ? catBtnActive : catBtn}
          >
            {cat}
          </button>
        ))}
      </div>

      {/* GRILLA DE PRODUCTOS MULTI-LOCAL */}
      <div style={gridStyle}>
        {loading ? (
          <p>Buscando las mejores ofertas...</p>
        ) : productosFiltrados.length > 0 ? (
          productosFiltrados.map(prod => (
            <div key={prod._id} style={cardStyle}>
              {/* Badge del Comercio */}
              <div style={localBadge}>
                <Store size={12} />
                <span>{prod.local?.nombre || 'Comercio'}</span>
              </div>

              <div style={imgWrapper}>
                <img 
                  src={`${URL_CARPETA_IMAGENES}${prod.publicId}.jpg`} 
                  alt={prod.producto}
                  style={imgStyle}
                  onError={(e) => { e.target.src = "https://via.placeholder.com/150?text=Sin+Imagen"; }}
                />
              </div>
              
              <div style={infoStyle}>
                <div style={{display: 'flex', justifyContent: 'space-between', alignItems: 'center'}}>
                    <span style={catTag}>{prod.categoria}</span>
                    <div style={distanciaTag}>
                        <MapPin size={10} />
                        <span>A 1.2km</span>
                    </div>
                </div>
                
                <h4 style={prodTitle}>{prod.producto}</h4>
                
                <div style={priceWrapper}>
                  <span style={currentPrice}>${prod.precioNuevo}</span>
                  {prod.precioViejo > prod.precioNuevo && (
                    <span style={oldPrice}>${prod.precioViejo}</span>
                  )}
                </div>

                <button style={addBtn}>Agregar al carrito</button>
              </div>
            </div>
          ))
        ) : (
          <div style={noResults}>
            <Filter size={40} color="#cbd5e1" />
            <p>No hay ofertas disponibles con esos filtros.</p>
          </div>
        )}
      </div>
    </div>
  );
};

// --- ESTILOS ACTUALIZADOS PARA MULTI-LOCAL ---
const containerStyle = { padding: '20px', background: '#f8fafc', minHeight: '100vh' };
const scrollCategories = { display: 'flex', gap: '10px', overflowX: 'auto', paddingBottom: '15px' };
const catBtn = { padding: '10px 20px', borderRadius: '25px', border: '1px solid #e2e8f0', background: 'white', cursor: 'pointer', color: '#64748b', fontWeight: 'bold', whiteSpace: 'nowrap' };
const catBtnActive = { ...catBtn, background: '#e67e22', color: 'white', borderColor: '#e67e22' };

const gridStyle = { display: 'grid', gridTemplateColumns: 'repeat(auto-fill, minmax(180px, 1fr))', gap: '20px', marginTop: '10px' };
const cardStyle = { background: 'white', borderRadius: '20px', border: '1px solid #e2e8f0', overflow: 'hidden', position: 'relative', boxShadow: '0 4px 6px -1px rgba(0,0,0,0.05)' };

const localBadge = { 
    position: 'absolute', top: '10px', left: '10px', zIndex: 5,
    background: 'rgba(30, 41, 59, 0.8)', color: 'white', 
    padding: '4px 10px', borderRadius: '12px', fontSize: '0.65rem',
    display: 'flex', alignItems: 'center', gap: '5px', backdropFilter: 'blur(4px)'
};

const imgWrapper = { width: '100%', height: '160px', background: '#fff', padding: '10px', boxSizing: 'border-box' };
const imgStyle = { width: '100%', height: '100%', objectFit: 'contain' };

const infoStyle = { padding: '15px', paddingTop: '0' };
const catTag = { fontSize: '0.6rem', color: '#e67e22', fontWeight: 'bold', textTransform: 'uppercase' };
const distanciaTag = { display: 'flex', alignItems: 'center', gap: '3px', color: '#94a3b8', fontSize: '0.6rem' };
const prodTitle = { fontSize: '0.9rem', margin: '8px 0', color: '#1e293b', fontWeight: '700', height: '40px', overflow: 'hidden' };
const priceWrapper = { display: 'flex', alignItems: 'center', gap: '8px', marginBottom: '12px' };
const currentPrice = { fontSize: '1.3rem', fontWeight: '900', color: '#1e293b' };
const oldPrice = { fontSize: '0.85rem', color: '#94a3b8', textDecoration: 'line-through' };
const addBtn = { width: '100%', padding: '12px', background: '#1e293b', color: 'white', border: 'none', borderRadius: '12px', cursor: 'pointer', fontWeight: 'bold', fontSize: '0.8rem' };
const noResults = { gridColumn: '1/-1', textAlign: 'center', padding: '100px', color: '#94a3b8' };

export default VistaCliente;
